    // Meaning: a reference valid longer IS-A reference valid shorter
    fn take_any(r: &str) { println!("{}", r); }
    take_any(s); // &'static used as &'short: covariant coercion

    // Memory: 'longer <: 'shorter (longer is the subtype)
    // Because the longer one satisfies the requirements of the shorter one
    println!("subtyping: longer lifetime is the subtype");
}

fn main() { explain_subtyping(); }

