use std::marker::PhantomData;
use std::alloc::{alloc, dealloc, Layout};

struct MyVec<T> {
    ptr: *mut T,
    len: usize,
    cap: usize,
    _marker: PhantomData<T>, // tells dropck we own T values
}

impl<T> MyVec<T> {
    fn new() -> Self {
        MyVec { ptr: std::ptr::NonNull::dangling().as_ptr(), len: 0, cap: 0, _marker: PhantomData }
    }
    fn with_capacity(cap: usize) -> Self {
        let layout = Layout::array::<T>(cap).unwrap();
        let ptr = unsafe { alloc(layout) as *mut T };
        MyVec { ptr, len: 0, cap, _marker: PhantomData }
    }
}

impl<T> Drop for MyVec<T> {
    fn drop(&mut self) {
        if self.cap > 0 {
            for i in 0..self.len {
                unsafe { std::ptr::drop_in_place(self.ptr.add(i)); }
            }
            let layout = Layout::array::<T>(self.cap).unwrap();
            unsafe { dealloc(self.ptr as *mut u8, layout); }
        }
    }
}

