use std::marker::PhantomData;

// COVARIANT in T: can use subtype (longer) where supertype (shorter) expected
struct Covariant<T>(_m: PhantomData<T>);

// CONTRAVARIANT in T: can use supertype (shorter) where subtype (longer) expected
struct Contravariant<T>(_m: PhantomData<fn(T)>);

// INVARIANT in T: must match exactly
struct Invariant<T>(_m: PhantomData<*mut T>);

// BIVARIANT (unused T): no constraint either way
struct Bivariant<T>(_m: PhantomData<fn() -> ()>, std::marker::PhantomData<T>);

fn covariant_demo() {
    // &'static str <: &'short str => Covariant<&'static> <: Covariant<&'short>
    let c: Covariant<&'static str> = Covariant(PhantomData);
    let _: Covariant<&str> = c; // OK
}

fn contravariant_demo() {
    // fn(&'short) <: fn(&'long): more general accepts shorter too
    fn accepts_any(_: &str) {}
    let f: fn(&'static str) = accepts_any; // fn(&str) -> fn(&'static str)
    let _ = f;
}

fn main() {
    covariant_demo();
    contravariant_demo();
    println!("All four variance kinds demonstrated");
    // Summary:
    // Covariant<T>:     T: SubType => Covariant<SubType>: Covariant<SuperType>
    // Contravariant<T>: T: SubType => Contravariant<SuperType>: Contravariant<SubType>
    // Invariant<T>:     must match exactly
    // Bivariant<T>:     T unused; no constraint
